int main() {
    int u, v;
    scanf("%d %d %d", &n, &u, &v);

    // Allocate memory for the adjacency list
    for(int i = 1; i <= n; i++) {
        adj[i] = (int*)malloc(N * sizeof(int));  // Allocating space for each node
        adj_size[i] = 0; // Initialize size of the adjacency list
    }

    // Input the tree edges
    for(int i = 1; i < n; i++) {
        int ui, vi;
        scanf("%d %d", &ui, &vi);
        adj[ui][adj_size[ui]++] = vi;
        adj[vi][adj_size[vi]++] = ui;
    }

    // Perform DFS from node 1
    dfs(1, -1, 0);
    preprocess();

    // Calculate and output the LCA of u and v
    printf("%d\n", lca(u, v));

    // Free dynamically allocated memory
    for(int i = 1; i <= n; i++) {
        free(adj[i]);
    }

    return 0;
