        }
    }

    static int lca(int u, int v) {
        if(level[u] < level[v]) {
            int temp = u;
            u = v;
            v = temp;
        }

        int k = level[u] - level[v];
        for(int j = 0; j < LG; j++) {
            if((k & (1 << j)) != 0) {
                u = ancestors[u][j];
            }
        }

        if(u == v)
            return v;

        for(int j = LG - 1; j >= 0; j--) {
            if(ancestors[u][j] != -1 && ancestors[u][j] != ancestors[v][j]) {
                u = ancestors[u][j];
                v = ancestors[v][j];
            }
        }

        return ancestors[u][0];
